    const revAdj: number[][] = Array.from({ length: n }, () => []);

    for (const [u, v, _] of edges) {
        fwAdj[u].push(v);
        revAdj[v].push(u);
    }

    const from0 = new Array(n).fill(false);
    const queue1 = [0];
    let ptr1 = 0;
    from0[0] = true;
    while (ptr1 < queue1.length) {
        const u = queue1[ptr1++];
        for (const v of fwAdj[u]) {
