                queue1.push(v);
            }
        }
    }

    const toN1 = new Array(n).fill(false);
    const queue2 = [n - 1];
    let ptr2 = 0;
    toN1[n - 1] = true;
    while (ptr2 < queue2.length) {
        const u = queue2[ptr2++];
        for (const w of revAdj[u]) {
            if (!toN1[w]) {
                toN1[w] = true;
                queue2.push(w);
            }
        }
    }

    const candidateNode = new Array(n).fill(false);
    for (let i = 0; i < n; i++) {
        if (from0[i] && toN1[i] && (i === 0 || i === n - 1 || online[i])) {
            candidateNode[i] = true;
        }
    }

    const candidateForward: [number, number][][] = Array.from({ length: n }, () => []);
    for (const [u, v, c] of edges) {
        if (candidateNode[u] && candidateNode[v]) {
            candidateForward[u].push([v, c]);
        }
    }

    const indegree = new Array(n).fill(0);
    for (let u = 0; u < n; u++) {
        for (const v of fwAdj[u]) {
            indegree[v]++;
        }
    }

    const topoOrder: number[] = [];
    const queue3: number[] = [];
    let ptr3 = 0;
    for (let i = 0; i < n; i++) {
        if (indegree[i] === 0) {
            queue3.push(i);
        }
    }

    while (ptr3 < queue3.length) {
        const u = queue3[ptr3++];
        topoOrder.push(u);
        for (const v of fwAdj[u]) {
            indegree[v]--;
            if (indegree[v] === 0) {
                queue3.push(v);
            }
        }
    }

    let maxCandidateCost = 0;
    for (const [u, v, c] of edges) {
        if (candidateNode[u] && candidateNode[v]) {
            if (c > maxCandidateCost) {
                maxCandidateCost = c;
            }
        }
    }

    const candidateCheck = (x: number): boolean => {
        const dist = new Array(n).fill(Number.MAX_SAFE_INTEGER);
        dist[0] = 0;

        for (const u of topoOrder) {
            if (!candidateNode[u]) continue;
            if (dist[u] === Number.MAX_SAFE_INTEGER) continue;

            for (const [v, c] of candidateForward[u]) {
                if (c < x) continue;
                const newDist = dist[u] + c;
                if (newDist > k) continue;
                if (newDist < dist[v]) {
                    dist[v] = newDist;
                }
            }
        }

        return dist[n - 1] <= k;
    };

    let low = 0;
    let high = maxCandidateCost;
    let ans = -1;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (candidateCheck(mid)) {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return ans;
}
