function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const validEdges: number[][] = edges.filter(edge => {
        const u = edge[0], v = edge[1];
        return online[u] && online[v];
    });

    let low = 0;
    let high = 10**9;
    let ans = -1;

    class MinHeap {
        private heap: [number, number][];

        constructor() {
            this.heap = [];
        }

        push(val: [number, number]): void {
            this.heap.push(val);
            this.bubbleUp(this.heap.length - 1);
        }

        private bubbleUp(index: number): void {
            if (index === 0) return;
            const element = this.heap[index];
            while (index > 0) {
                const parentIndex = Math.floor((index - 1) / 2);
                const parent = this.heap[parentIndex];
                if (parent[0] <= element[0]) break;
                this.heap[parentIndex] = element;
                this.heap[index] = parent;
                index = parentIndex;
            }
        }

        pop(): [number, number] | undefined {
            if (this.heap.length === 0) return undefined;
            const min = this.heap[0];
            const end = this.heap.pop();
            if (this.heap.length > 0 && end) {
                this.heap[0] = end;
                this.sinkDown(0);
            }
            return min;
        }

        private sinkDown(index: number): void {
            const length = this.heap.length;
            const element = this.heap[index];
            while (true) {
                const leftChildIndex = 2 * index + 1;
                const rightChildIndex = 2 * index + 2;
                let swap: number | null = null;
                let leftChild: [number, number] | undefined, rightChild: [number, number] | undefined;

                if (leftChildIndex < length) {
                    leftChild = this.heap[leftChildIndex];
                    if (leftChild[0] < element[0]) {
                        swap = leftChildIndex;
                    }
                }

                if (rightChildIndex < length) {
                    rightChild = this.heap[rightChildIndex];
                    if (
                        (swap === null && rightChild[0] < element[0]) || 
                        (swap !== null && leftChild && rightChild[0] < leftChild[0])
                    ) {
                        swap = rightChildIndex;
                    }
                }

                if (swap === null) break;
                this.heap[index] = this.heap[swap];
                this.heap[swap] = element;
                index = swap;
            }
        }

        isEmpty(): boolean {
            return this.heap.length === 0;
        }
    }

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const graph: [number, number][][] = Array.from({ length: n }, () => []);
        for (const edge of validEdges) {
            const u = edge[0], v = edge[1], cost = edge[2];
            if (cost >= mid) {
                graph[u].push([v, cost]);
            }
        }

        const dist = new Array(n).fill(Number.MAX_SAFE_INTEGER);
        dist[0] = 0;
        const heap = new MinHeap();
        heap.push([0, 0]);

