            const top = heap.pop();
            if (!top) break;
            const [d, u] = top;
            if (d !== dist[u]) continue;
            if (u === n - 1) break;
            for (const [v, w] of graph[u]) {
                const newDist = d + w;
                if (newDist < dist[v]) {
                    dist[v] = newDist;
                    heap.push([newDist, v]);
                }
            }
        }

        if (dist[n - 1] <= k) {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return ans;
}
